      updatedAt: string;
    };
  };
  meta: Meta;
}

export interface AssetDelta {
  beforeMinAsset: number;
  afterMinAsset: number;
  impactScore: number;
  riskLimit: number;
}

export interface TerminalOutcome {
  status: "accepted" | "rejected";
  reason?: string;
  code?: string;
}

export interface OrderResponse {
  command: {
    commandId: string;
    marketId: string;
    accountId: string;
    type: string;
    submittedAt: string;
  };
  order: {
    orderId: string;
    commandId: string;
    marketId: string;
    type: string;
  };
  assetDelta: AssetDelta;
  terminalOutcome: TerminalOutcome;
  meta: Meta;
}

export interface ApiError {
  error: {
    code: string;
